namespace DocSummary.Models;

public class SummarizeRequest
{
    public required string Text { get; set; }
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizer
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "from", "it",
        "this", "that", "which", "who", "whom", "has", "have", "had", "be",
        "been", "being", "do", "does", "did", "will", "would", "could",
        "should", "may", "might", "shall", "can", "not", "no", "as", "if",
        "then", "than", "so", "up", "out", "about", "into", "over", "after"
    };

    public string Summarize(string text, int maxSentences)
    {
        var sentences = SplitSentences(text);
        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var scored = sentences
            .Select((sentence, index) => (Sentence: sentence, Score: ScoreSentence(sentence, wordFrequencies), Index: index))
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index) // preserve original order
            .Select(s => s.Sentence);

        return string.Join(" ", scored);
    }

    private static List<string> SplitSentences(string text)
    {
        return SentenceRegex().Matches(text)
            .Select(m => m.Value.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in WordRegex().Matches(sentence).Select(m => m.Value))
            {
                if (word.Length > 1 && !StopWords.Contains(word))
                    freq[word] = freq.GetValueOrDefault(word) + 1;
            }
        }
        return freq;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
    {
        var words = WordRegex().Matches(sentence).Select(m => m.Value).ToList();
        if (words.Count == 0) return 0;

        double score = words
            .Where(w => !StopWords.Contains(w))
            .Sum(w => wordFrequencies.GetValueOrDefault(w));

        return score / words.Count;
    }

    [GeneratedRegex(@"[^.!?]*[.!?]+", RegexOptions.Compiled)]
    private static partial Regex SentenceRegex();

    [GeneratedRegex(@"\w+", RegexOptions.Compiled)]
    private static partial Regex WordRegex();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly DocumentSummarizer _summarizer;

    public SummarizeController(DocumentSummarizer summarizer)
    {
        _summarizer = summarizer;
    }

    [HttpPost]
    public IActionResult Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Text))
            return BadRequest(new { error = "Text is required." });

        if (request.MaxSentences < 1)
            return BadRequest(new { error = "MaxSentences must be at least 1." });

        var summary = _summarizer.Summarize(request.Text, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.Text.Length,
            SummaryLength = summary.Length
        });
    }
}

